What does this program print?

```cpp
#include <iostream>
int main() {
    int** g = new int*[2];
    g[0] = new int[3]{1, 2, 3};
    g[1] = new int[3]{4, 5, 6};
    std::cout << g[0][2] << " " << g[1][0] << "\n";
    for (int r = 0; r < 2; ++r) delete[] g[r];
    delete[] g;
}
```

This program has a memory management bug. What is it?

```cpp
int rows = 3, cols = 4;
int** g = new int*[rows];
for (int r = 0; r < rows; ++r)
    g[r] = new int[cols]{};

// cleanup
delete[] g;                       // (1)
for (int r = 0; r < rows; ++r)    // (2)
    delete[] g[r];
```
